import java.io.*;
import java.math.BigInteger;
import java.util.*;

public class Main {
    private static BigInteger fastPower(BigInteger base, int exponent) {
        BigInteger result = BigInteger.ONE;
        while (exponent > 0) {
            if ((exponent & 1) == 1) {
                result = result.multiply(base);
            }
            base = base.multiply(base);
            exponent >>= 1;
        }
        return result;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawInput = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawInput.append(line).append(' ');
        }
        String all = rawInput.toString().trim();
        // Replace escaped newline literals with spaces to handle inputs like "1\\n2 3"
        all = all.replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(all);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder output = new StringBuilder();
        for (int i = 0; i < T; i++) {
            if (!st.hasMoreTokens()) break;
            BigInteger base = new BigInteger(st.nextToken());
            int exp = Integer.parseInt(st.nextToken());
            output.append(fastPower(base, exp)).append('\n');
        }
        System.out.print(output.toString());
    }
}

